mapper.select:
select a.*, b.employee_name from hrm_bonus as a left join hrm_employee as b
on a.employee_id = b.employee_id
WHERE 1=1

    AND a.employee_id in (select employee_id from hrm_employee where employee_Name like concat('%',#{data.employeeName},'%'))


    AND a.year = #{data.year}


    AND a.month = #{data.month}
